for (const item of items) {

  // ===== Name =====
  const name = (item.json.name || "")
    .trim()
    .toLowerCase()
    .replace(/\b\w/g, c => c.toUpperCase());

  // ===== Email =====
  const email = (item.json.email || "")
    .trim()
    .toLowerCase();

  const emailRegex =
    /^(?!.*\.\.)[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\.[A-Za-z]{2,}$/;

  // ===== Phone Function =====
  function normalizePhone(raw) {
    if (!raw) return { valid: false };

    let phone = raw.replace(/[^\d+]/g, "")
                   .replace(/(?!^)\+/g, "");

    let country = "Unknown";

    if (phone.startsWith("+")) {
      const digits = phone.replace(/\D/g, "");
      return {
        valid: digits.length >= 8 && digits.length <= 15,
        phone,
        country: "international"
      };
    }

    const digits = phone.replace(/\D/g, "");

    if (digits.length === 9 && digits.startsWith("5")) {
      return {
        valid: true,
        phone: "+971" + digits,
        country: "UAE"
      };
    }

    return { valid: false };
  }

  // ===== APPLY PHONE =====
  const phoneResult = normalizePhone(item.json.phone);

  const source = (item.json.source || "").trim();
  const serviceNeeded = (item.json.service_needed || "").trim();

  // ==========================
  // Validation
  // ==========================

  const missing = [];

  if (!name) missing.push("name");
  if (!email) missing.push("email");
  if (!phoneResult.valid) missing.push("phone");
  if (!source) missing.push("source");
  if (!serviceNeeded) missing.push("service_needed");

  if (missing.length) {
    item.json = {
      valid: false,
      reason: `${missing.join(", ")} ${
        missing.length === 1 ? "is" : "are"
      } missing`
    };
    continue;
  }

  // Email validation
  if (!emailRegex.test(email)) {
    item.json = {
      valid: false,
      reason: "email is invalid"
    };
    continue;
  }

  // Success
  item.json = {
    valid: true,
    name,
    email,
    phone: phoneResult.phone,
    country: phoneResult.country,
    source,
    service_needed: serviceNeeded
  };
}

return items;

